### `public/sw.js` (new, plain JS)
```js
const CACHE_NAME = 'move-v1'
self.addEventListener('install', (e) => self.skipWaiting())
// activate: delete every cache whose name !== CACHE_NAME, then clients.claim().
self.addEventListener('activate', (e) => { /* caches.keys() -> delete non-matching; clients.claim() */ })
// fetch: GET only, same-origin.
//   navigations / HTML: NETWORK-FIRST (on failure, cached response / cached '/').
//   hashed build assets (/assets/...): CACHE-FIRST.
//   other same-origin GET: STALE-WHILE-REVALIDATE.
self.addEventListener('fetch', (e) => { /* ... */ })
// notificationclick: event.notification.close(); then waitUntil:
//   const data = event.notification.data (occurrenceId, exerciseId); action = event.action.
//   const all = await clients.matchAll({ type:'window', includeUncontrolled:true });
//   if a client exists: focus it and postMessage({ type:'reminder-action', action, exerciseId, occurrenceId }).
//   else: enqueue the action (Cache or IndexedDB), then clients.openWindow('/'); deliver the queued
//         action once the newly loaded client posts { type:'client-ready' }.
self.addEventListener('notificationclick', (e) => { /* ... */ })
// message: on { type:'client-ready' } from a client, flush any queued actions to that client.
self.addEventListener('message', (e) => { /* ... */ })
```

